/** Parse CSS color → { r, g, b, a } (0-1 range). */
function parseCssColor(str) {
  const rgba = str.match(/rgba?\(\s*([\d.]+)\s*,\s*([\d.]+)\s*,\s*([\d.]+)(?:\s*,\s*([\d.]+))?\s*\)/);
  if (rgba) {
    return {
      r: parseFloat(rgba[1]) / 255, g: parseFloat(rgba[2]) / 255,
      b: parseFloat(rgba[3]) / 255, a: rgba[4] !== undefined ? parseFloat(rgba[4]) : 1,
    };
  }
  const hex = str.match(/^#([0-9a-fA-F]{3,8})$/);
  if (hex) {
    let h = hex[1];
    if (h.length === 3) h = h.split('').map(c => c + c).join('');
    return {
      r: parseInt(h.slice(0,2),16)/255, g: parseInt(h.slice(2,4),16)/255,
      b: parseInt(h.slice(4,6),16)/255, a: h.length===8 ? parseInt(h.slice(6,8),16)/255 : 1,
    };
  }
  return null;
}

