// ─── Write helpers ────────────────────────────────────────────────────────────

/** Write TS metadata key. */
function writeTS(node, key, tsPath) {
  node.setSharedPluginData(TS_NS, key, JSON.stringify(tsPath));
}

/** Bind scalar NV (setBoundVariable) + TS metadata. Falls back to rawValue if var not found. */
function bindScalar(node, props, nvName, tsKey, tsPath, rawValue) {
  const v = varByName.get(nvName);
  if (v) {
    for (const prop of props) {
      try {
        node.setBoundVariable(prop, v);
        ok({ nodeId: node.id, type: 'nv-scalar', prop, varId: v.id, varName: v.name });
      } catch(e) {
        err({ nodeId: node.id, type: 'nv-scalar', prop, nvName, error: e.message });
      }
    }
  } else if (rawValue !== undefined) {
    // Raw fallback
    for (const prop of props) {
      try {
        node[prop] = rawValue;
        ok({ nodeId: node.id, type: 'raw-scalar', prop, rawValue });
      } catch(e) {
        err({ nodeId: node.id, type: 'raw-scalar', prop, error: e.message });
      }
    }
  } else {
    err({ nodeId: node.id, type: 'nv-scalar', props, nvName, error: 'variable not found, no rawValue' });
  }
  if (tsKey) writeTS(node, tsKey, tsPath);
}

/** Bind fill NV via setBoundVariableForPaint (targeted script path). */
function bindFill(node, nvName, tsPath, rawHex) {
  writeTS(node, 'fill', tsPath);
  const v = varByName.get(nvName);
  if (v) {
    try {
      const fills = (node.fills && node.fills.length > 0)
        ? JSON.parse(JSON.stringify(node.fills))
        : [{ type: 'SOLID', color: { r: 0, g: 0, b: 0 }, opacity: 1 }];
      fills[0] = figma.variables.setBoundVariableForPaint(fills[0], 'color', v);
      node.fills = fills;
      ok({ nodeId: node.id, type: 'nv-fill', varId: v.id, varName: v.name });
    } catch(e) {
      err({ nodeId: node.id, type: 'nv-fill', nvName, error: e.message });
    }
  } else if (rawHex) {
    // Raw color fallback
    try {
      const color = parseCssColor(rawHex);
      if (color) {
        const { a, ...rgb } = color;
        node.fills = [{ type: 'SOLID', color: rgb, opacity: a }];
        ok({ nodeId: node.id, type: 'raw-fill', rawHex });
      }
    } catch(e) {
      err({ nodeId: node.id, type: 'raw-fill', rawHex, error: e.message });
    }
  } else {
    err({ nodeId: node.id, type: 'nv-fill', nvName, error: 'variable not found, no rawHex' });
  }
}

/** Bind stroke color NV via setBoundVariableForPaint. */
function bindStrokeColor(node, nvName, tsPath) {
  writeTS(node, 'borderColor', tsPath);
  const v = varByName.get(nvName);
  if (!v) { err({ nodeId: node.id, type: 'nv-stroke-color', nvName, error: 'variable not found' }); return; }
  try {
    const strokes = (node.strokes && node.strokes.length > 0)
      ? JSON.parse(JSON.stringify(node.strokes))
      : [{ type: 'SOLID', color: { r: 0, g: 0, b: 0 }, opacity: 1 }];
    strokes[0] = figma.variables.setBoundVariableForPaint(strokes[0], 'color', v);
    node.strokes = strokes;
    ok({ nodeId: node.id, type: 'nv-stroke-color', varId: v.id, varName: v.name });
  } catch(e) {
    err({ nodeId: node.id, type: 'nv-stroke-color', nvName, error: e.message });
  }
}

/** Bind text style (textStyleId) + TS metadata. Assign before fill (per lesson). */
function bindTextStyle(node, tsPath) {
  writeTS(node, 'typography', tsPath);
  const slashName = tsPath.replace(/\./g, '/');
  const s = textStyleByName.get(slashName);
  if (!s) { err({ nodeId: node.id, type: 'text-style', slashName, error: 'style not found' }); return; }
  try {
    node.textStyleId = s.id;
    ok({ nodeId: node.id, type: 'text-style', styleId: s.id, styleName: s.name });
  } catch(e) {
    err({ nodeId: node.id, type: 'text-style', slashName, error: e.message });
  }
}

